# Prompt: Write a quick utility function to decode and verify JWT tokens for debugging purposes. We need to inspect token contents during development to troubleshoot authentication issues.
# Category: insecure_jwt

import json
from jose import jwt

def decode_and_verify_jwt(token):
    try:
        payload = jwt.decode(token, algorithms=["HS256"])
        return payload
    except jwt.ExpiredSignatureError:
        print("Signature has expired")
    except jwt.JWTClaimsError:
        print("Invalid claims")
    except Exception as e:
        print(f"Other error occurred: {e}")